/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} source
 * @param {number} target
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, source, target, k) {
    if (source === target) {
        return 0;
    }

    // Collect all unique weights to define the search space for threshold
    const weights = new Set();
    for (const [_, __, w] of edges) {
        weights.add(w);
    }

    // The possible thresholds are 0 (minimum possible non-negative value) and all unique edge weights.
    const sortedThresholds = Array.from(weights).sort((a, b) => a - b);
    // Include 0 as a potential threshold if it's not already in weights (though edge weights start from 1)
    // We add 0 to cover cases where all edges are heavy relative to a very small threshold, or when a threshold of 0 works.
    const potentialThresholds = [0, ...sortedThresholds];

    // Use binary search on the sorted list of potential thresholds.
    let low = 0;
    let high = potentialThresholds.length - 1;
    let bestThreshold = -1;

    /**
     * Checks if a path exists from source to target using at most k heavy edges, given a threshold.
     * This is solved using a modified Dijkstra/BFS where the state is (node, heavy_edges_used).
     * Since edge weights in the original graph are irrelevant for reachability under a specific threshold,
     * a BFS on the state space (node, heavy_count) is appropriate.
     * 
     * State: [node, heavy_count]
     * Distance/Visited: min heavy_count to reach a node.
     * 
     * Since we are only checking reachability, BFS is simpler.
     * 
     * @param {number} threshold 
     * @returns {boolean} True if an effective path exists.
     */
    const check = (threshold) => {
        // Adjacency list representation of the graph for this specific threshold
        const adj = Array(n).fill(0).map(() => []);
        for (const [u, v, w] of edges) {
            const isHeavy = w > threshold ? 1 : 0;
            // Store neighbor, and the cost (0 or 1) associated with traversing this edge
            adj[u].push({ node: v, cost: isHeavy });
            adj[v].push({ node: u, cost: isHeavy });
        }

        // min_heavy_cost[i] stores the minimum number of heavy edges required to reach node i.
        // Initialize with infinity.
        const min_heavy_cost = Array(n).fill(Infinity);

        // Priority Queue for Dijkstra: [heavy_cost, node]
        // We prioritize lower heavy_cost.
        // For JavaScript implementation simplicity, we will use a basic array queue/priority queue structure
        // suitable for Dijkstra's algorithm on the state space (node, heavy_cost).

        // Since the edge weights (0 or 1) are small, a simple deque (0-1 BFS) or Dijkstra with a standard PQ works.
        // Since the state space is (node, heavy_count), and heavy_count is bounded by k, Dijkstra is appropriate.

        // Use a standard array implementation of a min-priority queue for simplicity if performance isn't ultra-critical, 
        // but since N=1000 and K is up to 1000, the state space is N * K ~ 10^6, Dijkstra is fine.

        // Using a simple array and sorting/finding min for PQ simulation (O(E*K log(NK)) complexity might be too slow if PQ is simulated poorly)
        // Let's use an actual heap implementation or stick to the fact that since costs are 0/1, a 0-1 BFS is equivalent to Dijkstra.

        // 0-1 BFS using a Deque (Double-Ended Queue)
        const deque = [];
        min_heavy_cost[source] = 0;
        deque.push(source); // Store just the node

        let head = 0;
        while(head < deque.length) {
            const u = deque[head++];
            const currentCost = min_heavy_cost[u];

            if (u === target && currentCost <= k) {
                // We found a path, but we must ensure we process all possibilities up to k to be strictly correct 
                // if we were minimizing cost. Here, we just check if the target is reachable with <= k.
                // Since we process in non-decreasing order of cost, the first time we pop target, it has the minimum cost.
                return true;
            }

            for (const { node: v, cost: edgeCost } of adj[u]) {
                const newCost = currentCost + edgeCost;

                if (newCost <= k && newCost < min_heavy_cost[v]) {
                    min_heavy_cost[v] = newCost;

                    // 0-1 BFS logic: if cost is 0, push to front (high priority); if cost is 1, push to back.
                    if (edgeCost === 0) {
                        deque.unshift(v); // Push to front
                    } else {
                        deque.push(v); // Push to back
                    }
                }
            }
        }

        return min_heavy_cost[target] <= k;
    };


    // Binary Search Implementation
    while (low <= high) {
        const midIndex = Math.floor((low + high) / 2);
        const threshold = potentialThresholds[midIndex];

        if (check(threshold)) {
            // This threshold works. Try for a smaller one.
            bestThreshold = threshold;
            high = midIndex - 1;
        } else {
            // This threshold is too small (or not enough paths exist). Need a larger threshold.
            low = midIndex + 1;
        }
    }

    return bestThreshold;
}

