#include <vector>
#include <algorithm>
#include <set>
#include <map>
#include <deque>

using namespace std;

// Helper struct for adjacency list entries
struct EdgeInfo {
    int node;
    int cost; // 0 for light, 1 for heavy
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long source, long long target, long long k) {
    if (source == target) {
        return 0;
    }

    // Collect all unique weights
    std::set<long long> weights_set;
    for (const auto& edge : edges) {
        long long w = edge[2];
        weights_set.insert(w);
    }

    // Potential thresholds: 0 and all unique edge weights
    std::vector<long long> potential_thresholds;
    potential_thresholds.push_back(0);
    for (long long w : weights_set) {
        potential_thresholds.push_back(w);
    }
    std::sort(potential_thresholds.begin(), potential_thresholds.end());

    // Remove duplicates just in case (though set insertion handles most of this)
    potential_thresholds.erase(std::unique(potential_thresholds.begin(), potential_thresholds.end()), potential_thresholds.end());


    /**
     * Checks if a path exists from source to target using at most k heavy edges, given a threshold.
     * Uses 0-1 BFS (a specialized shortest path algorithm for edge weights 0 or 1).
     */
    auto check = [&](long long threshold) -> bool {
        // Adjacency list representation
        std::vector<std::vector<EdgeInfo>> adj(n);
        for (const auto& edge : edges) {
            long long u = edge[0];
            long long v = edge[1];
            long long w = edge[2];

            // cost = 1 if heavy (w > threshold), 0 otherwise (w <= threshold)
            int is_heavy = (w > threshold) ? 1 : 0;

            // Undirected graph
            adj[u].push_back({(int)v, is_heavy});
            adj[v].push_back({(int)u, is_heavy});
        }

        // min_heavy_cost[i] stores the minimum number of heavy edges required to reach node i.
        // Initialize with a value greater than k (since we only care up to k).
        std::vector<int> min_heavy_cost(n, k + 1);

        // 0-1 BFS using a Deque
        std::deque<int> dq;

        min_heavy_cost[source] = 0;
        dq.push_back((int)source);

        while (!dq.empty()) {
            int u = dq.front();
            dq.pop_front();

            int current_cost = min_heavy_cost[u];

            if (u == target) {
                // Since 0-1 BFS finds the shortest path first, if we reach target, 
                // we know the minimum cost.
                return current_cost <= k;
            }

            for (const auto& edge : adj[u]) {
                int v = edge.node;
                int edge_cost = edge.cost;
                int new_cost = current_cost + edge_cost;

                // We only proceed if the new cost is within the limit k and is an improvement
                if (new_cost <= k && new_cost < min_heavy_cost[v]) {
                    min_heavy_cost[v] = new_cost;

                    // 0-1 BFS logic: cost 0 -> push front; cost 1 -> push back.
                    if (edge_cost == 0) {
                        dq.push_front(v);
                    } else {
                        dq.push_back(v);
                    }
                }
            }
        }

        return min_heavy_cost[target] <= k;
    };


    // Binary Search on the potential thresholds
    long long best_threshold = -1;
    int low = 0;
    int high = potential_thresholds.size() - 1;

    while (low <= high) {
        int mid_index = low + (high - low) / 2;
        long long threshold = potential_thresholds[mid_index];

        if (check(threshold)) {
            // This threshold works. Record it and try for a smaller one.
            best_threshold = threshold;
            high = mid_index - 1;
        } else {
            // This threshold is too small. Need a larger threshold.
            low = mid_index + 1;
        }
    }

    return best_threshold;
}

